public int dotProduct(Map<Integer, Integer> vec1, Map<Integer, Integer> vec2) {
    if (vec2.size() < vec1.size()) {
        var tmp = vec1;
        vec1 = vec2;
        vec2 = tmp;
    }
    int product = 0;
    for (var entry : vec1.entrySet()) {
        product += vec2.getOrDefault(entry.getKey(), 0) * entry.getValue();
    }
    return product;
}
